                  <span className="block text-3xl font-bold gradient-text">{plan.credits}</span>
                  <span className="text-[11px] text-gray-600 uppercase font-bold tracking-wider">Cr{'\u00e9'}dits Gas</span>
                </div>
              </div>

              <h3 className="text-xl font-bold text-white mb-2">{plan.name}</h3>
              <div className="flex items-baseline gap-1 mb-8">
                <span className="text-4xl font-bold text-white">{plan.price}{'\u20ac'}</span>
                <span className="text-sm text-gray-600">HT</span>
              </div>

              <ul className="space-y-3.5 mb-8 flex-1">
                {plan.features.map((feat, i) => (
                  <li key={i} className="flex items-start gap-3 text-[15px] text-gray-400">
                    <Check size={16} className={`mt-0.5 shrink-0 ${plan.popular ? 'text-purple-400' : 'text-gray-600'}`} />
                    {feat}
                  </li>
                ))}
              </ul>

              <button
                onClick={() => handleSelectPlan(plan.id)}
                className={`w-full py-3.5 rounded-full font-bold flex items-center justify-center gap-2 transition-all text-[15px] cursor-pointer ${
                  plan.popular
                    ? 'btn-gradient shadow-lg shadow-purple-600/25'
                    : 'bg-white/[0.04] border border-white/[0.08] text-gray-300 hover:bg-white/[0.07] hover:border-white/[0.12]'
                }`}
              >
                {user ? 'Recharger' : 'Cr\u00e9er un compte'} <ArrowRight size={16} />
              </button>
            </div>
          ))}
        </div>
      </section>

      {/* ── FINAL CTA SECTION ── */}
      <section className="mt-20 mb-8 max-w-5xl mx-auto">
        <div className="gradient-border p-10 md:p-16 text-center relative overflow-hidden">
          {/* Grid pattern */}
          <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'linear-gradient(rgba(255, 255, 255, 0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(255, 255, 255, 0.02) 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>
          {/* Ambient glows */}
          <div className="section-glow top-0 right-0 w-[300px] h-[300px] bg-purple-600/[0.08]"></div>
          <div className="section-glow bottom-0 left-0 w-[300px] h-[300px] bg-violet-600/[0.06]"></div>

          <div className="relative z-10">
            <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
              Pr{'\u00ea'}t {'\u00e0'} dominer les <span className="gradient-text">r{'\u00e9'}ponses IA</span> ?
            </h2>
            <p className="text-gray-400 max-w-xl mx-auto text-lg mb-10">
              Rejoignez les marques qui se font citer par ChatGPT, Claude et Gemini. Gratuit pour commencer, aucune carte bancaire requise.
            </p>
            <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
              <button onClick={handleStartAnalysis} className="w-full sm:w-auto btn-gradient text-base px-8 py-3.5 flex items-center justify-center gap-2.5 shadow-lg shadow-purple-600/25 cursor-pointer">
                Commencer gratuitement <ArrowRight size={18} />
              </button>
              <button onClick={() => onNavigate('directory')} className="w-full sm:w-auto px-8 py-3.5 rounded-full glass-card text-gray-200 text-base font-medium hover:bg-white/[0.08] transition-all cursor-pointer">
                Explorer l'Annuaire
              </button>
            </div>
          </div>
        </div>
      </section>

    </div>
  );
};

export default Home;
"}

